class IoTApiService(private val httpClient: IoTHttpClient) {

    suspend fun registerDevice(deviceId: String, deviceName: String, authToken: String): Boolean {
        val json = JSONObject().apply {
            put("device_id", deviceId)
            put("device_name", deviceName)
        }.toString()

        return try {
            val response = httpClient.syncWithCloud("/devices/register", json, authToken)
            response.isSuccessful
        } catch (e: Exception) {
            false
        }
    }

    suspend fun getDeviceList(authToken: String): List<Device> {
        return try {
            val response = httpClient.fetchCloudData("/devices", authToken)
            if (response.isSuccessful) {
                val body = response.body?.string()
                body?.let { parseDeviceList(it) } ?: emptyList()
            } else {
                emptyList()
            }
        } catch (e: Exception) {
            emptyList()
        }
    }

    suspend fun sendTelemetry(deviceId: String, data: Map<String, Any>, authToken: String): Boolean {
        val json = JSONObject().apply {
            put("device_id", deviceId)
            put("timestamp", System.currentTimeMillis())
            data.forEach { (key, value) ->
                put(key, value)
            }
        }.toString()

        return try {
            val response = httpClient.syncWithCloud("/telemetry", json, authToken)
            response.isSuccessful
        } catch (e: Exception) {
            false
        }
    }

    private fun parseDeviceList(json: String): List<Device> {
        val devices = mutableListOf<Device>()
        val jsonObject = JSONObject(json)
        val devicesArray = jsonObject.optJSONArray("devices") ?: return emptyList()

        for (i in 0 until devicesArray.length()) {
            val deviceObj = devicesArray.getJSONObject(i)
            devices.add(
                Device(
                    id = deviceObj.optString("id"),
                    name = deviceObj.optString("name"),
                    ipAddress = deviceObj.optString("ip_address"),
                    type = deviceObj.optString("type")
                )
            )
        }
        return devices
    }
}

data class Device(
    val id: String,
    val name: String,
    val ipAddress: String,
    val type: String
)